protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 renamed the default discriminator property from "Discriminator"
        // to "$type". Preserve the old name so existing documents and direct SQL
        // queries that reference c.Discriminator continue to work.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 no longer embeds the discriminator in the JSON id property.
        // Preserve the old "Product|123" format so existing documents remain
        // accessible via FindAsync / point-reads.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // HasIndex was removed — it now throws at startup for the Cosmos provider.
    // Manage indexing through the container's indexing policy in Azure Portal,
    // Bicep, or Terraform instead.
}

